const results = [];
for (const inputItem of $input.all()) {
  let ideas = inputItem.json.output || inputItem.json.content;
  if (typeof ideas === 'string') {
    try {
      ideas = JSON.parse(ideas);
    } catch (e) {
      continue;
    }
  }
  if (!Array.isArray(ideas)) continue;

  for (const idea of ideas) {
    results.push({
      json: {
        title: idea.title || '',
        keywords: idea.keywords || '',
        category_slug: idea.category_slug || 'ecommerce',
        meta_description: idea.meta_description || '',
        status: 'pending'
      }
    });
  }
}
return results;
